import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
        kind = e.get('event', e.get('kind', '?'))
        ts = e.get('ts', '?')
        run = e.get('run_id', '?')[:8]
        if kind in ('RunStarted', 'RunCompleted', 'SessionStarted', 'FailureObserved', 'TaskStarted', 'TaskCompleted', 'TaskRevert'):
            print(f'{ts} {run} {kind}: {json.dumps(e.get(\"payload\", {}), default=str)[:200]}')
    except:
        pass
" 2>&1 | tail -30

