import sys, json
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        e = json.loads(line)
        kind = e.get('event', e.get('kind', '?'))
        ts = e.get('ts', '?')
        payload = e.get('payload', {})
        run_id = payload.get('_yoyo', {}).get('run_id', '?')
        # Look for the recent runs
        if '17815358' in str(run_id) or 'FailureObserved' in kind:
            print(f'{kind} run={run_id[-12:]} payload_keys={list(payload.keys())[:8]}')
            if kind == 'FailureObserved':
                print(f'  FAILURE: {json.dumps(payload, default=str)[:500]}')
    except Exception as ex:
        pass
" 2>&1

